Object.keys(SSAI_COMPLETION).forEach(code => {
  window.SSAI_GLOBAL_EXTRA[code] = Object.assign(window.SSAI_GLOBAL_EXTRA[code] || {}, SSAI_COMPLETION[code]);
});

function ssaiGetLang() {
  let stored = 'en';
  try { stored = localStorage.getItem(SSAI_KEY) || 'en'; } catch(e) {}
  return SSAI_ALLOWED.includes(stored) ? stored : 'en';
}

function ssaiGetValue(code, key) {
  const G = (window.SSAI_GLOBAL_EXTRA && window.SSAI_GLOBAL_EXTRA[code]) || {};
  const GE = (window.SSAI_GLOBAL_EXTRA && window.SSAI_GLOBAL_EXTRA.en) || {};
  const T = (window.SSAI_T && window.SSAI_T[code]) || {};
  const E = (window.SSAI_T && window.SSAI_T.en) || {};
  if (code === 'en') {
    if (G[key] !== undefined) return G[key];
    if (T[key] !== undefined) return T[key];
    if (E[key] !== undefined) return E[key];
    return key;
  }
  if (G[key] !== undefined && (GE[key] === undefined || G[key] !== GE[key])) return G[key];
  if (T[key] !== undefined) return T[key];
  if (G[key] !== undefined) return G[key];
  if (GE[key] !== undefined) return GE[key];
  if (E[key] !== undefined) return E[key];
  return key;
}
function ssaiT(key) { return ssaiGetValue(SSAI_LANG, key); }

function ssaiApply(code) {
  code = SSAI_ALLOWED.includes(code) ? code : 'en';
  SSAI_LANG = code;
  document.documentElement.setAttribute('lang', code);
  document.documentElement.setAttribute('dir', SSAI_RTL.includes(code) ? 'rtl' : 'ltr');
  document.querySelectorAll('[data-i18n]').forEach(el => { el.textContent = ssaiGetValue(code, el.dataset.i18n); });
  document.querySelectorAll('[data-i18n-html]').forEach(el => { el.innerHTML = ssaiGetValue(code, el.dataset.i18nHtml); });
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el => { el.placeholder = ssaiGetValue(code, el.dataset.i18nPlaceholder); });
  document.querySelectorAll('[data-i18n-title]').forEach(el => { el.title = ssaiGetValue(code, el.dataset.i18nTitle); });
  document.dispatchEvent(new CustomEvent('ssai:lang', { detail: { code, get: key => ssaiGetValue(code, key) } }));
}

function ssaiLoadLang(code, cb) {
  code = SSAI_ALLOWED.includes(code) ? code : 'en';
  if (window.SSAI_T && window.SSAI_T[code]) { if (cb) cb(); return; }
  if (code === 'en') { if (cb) cb(); return; }
  const existing = document.querySelector('script[data-ssai-lang="'+code+'"]');
  if (existing) { existing.addEventListener('load', () => cb && cb()); return; }
  const s = document.createElement('script');
  s.src = 'lang/' + code + '.js';
  s.dataset.ssaiLang = code;
  s.onload = () => { if (cb) cb(); };
  s.onerror = () => { if (cb) cb(); };
  document.head.appendChild(s);
}

function ssaiSetLang(code) {
  code = SSAI_ALLOWED.includes(code) ? code : 'en';
  SSAI_LANG = code;
  try { localStorage.setItem(SSAI_KEY, code); } catch(e) {}
  ssaiLoadLang(code, () => {
    ssaiApply(code);
    _ssaiUpdateBtn(code);
    const dd = document.getElementById('ssai-dd');
    if (dd) dd.style.display = 'none';
  });
}

function _ssaiUpdateBtn(code) {
  const btn = document.getElementById('ssai-lang-label');
  if (btn) btn.innerHTML = '<img src="https://flagcdn.com/w40/'+SSAI_FLAGS[code]+'.png" style="height:14px;width:auto;margin-right:7px;vertical-align:middle;border-radius:2px;" alt=""/>'+SSAI_LANGS[code];
  document.querySelectorAll('[data-lang-opt]').forEach(el => {
    const active = el.dataset.langOpt === code;
    el.style.color = active ? '#C4A55A' : 'rgba(255,255,255,.62)';
    el.style.background = active ? 'rgba(196,165,90,.09)' : '';
    el.style.fontWeight = active ? '800' : '600';
  });
}

function ssaiToggle(e) {
  if (e) e.stopPropagation();
  const dd = document.getElementById('ssai-dd');
  if (dd) dd.style.display = dd.style.display === 'block' ? 'none' : 'block';
}

function ssaiRender(hostId) {
  const host = document.getElementById(hostId);
  if (!host) return;
  const opts = SSAI_ALLOWED.map(code => `
    <button data-lang-opt="${code}" onclick="ssaiSetLang('${code}')"
      style="display:flex;align-items:center;width:100%;text-align:left;padding:8px 11px;font-size:12.5px;color:rgba(255,255,255,.62);background:none;border:none;cursor:pointer;font-family:'Inter',sans-serif;border-radius:7px;line-height:1.5;font-weight:650;transition:background .15s,color .15s;">
      <img src="https://flagcdn.com/w40/${SSAI_FLAGS[code]}.png" style="height:14px;width:auto;margin-right:9px;flex-shrink:0;border-radius:2px;" alt=""/>${SSAI_LANGS[code]}
    </button>`).join('');
  host.innerHTML = `
    <div translate="no" class="notranslate" style="position:relative;display:inline-block;">
      <button onclick="ssaiToggle(event)" style="display:flex;align-items:center;gap:7px;padding:7px 12px;border-radius:10px;border:1px solid rgba(255,255,255,.1);background:rgba(255,255,255,.04);color:rgba(255,255,255,.66);font-size:12px;font-weight:750;cursor:pointer;font-family:'Inter',sans-serif;white-space:nowrap;box-shadow:0 12px 34px rgba(0,0,0,.22);">
        <svg width="13" height="13" fill="none" stroke="currentColor" viewBox="0 0 24 24" style="opacity:.7;flex-shrink:0;"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M3 5h12M9 3v2m1.048 9.5A18.022 18.022 0 016.412 9m6.088 9h7M11 21l5-10 5 10M12.751 5C11.783 10.77 8.07 15.61 3 18.129"/></svg>
        <span id="ssai-lang-label">English</span>
        <svg width="9" height="9" fill="none" stroke="currentColor" viewBox="0 0 24 24" style="opacity:.4;flex-shrink:0;"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2.5" d="M19 9l-7 7-7-7"/></svg>
      </button>
      <div id="ssai-dd" style="display:none;position:absolute;top:calc(100% + 6px);right:0;width:190px;z-index:9999;background:#141416;border:1px solid rgba(255,255,255,.1);border-radius:12px;padding:6px;box-shadow:0 20px 60px rgba(0,0,0,.75);">${opts}</div>
    </div>`;
  document.addEventListener('click', e => { if (!host.contains(e.target)) { const dd = document.getElementById('ssai-dd'); if (dd) dd.style.display = 'none'; } });
  _ssaiUpdateBtn(SSAI_LANG);
}

function initLang(hostId) {
  SSAI_LANG = ssaiGetLang();
  ssaiLoadLang(SSAI_LANG, () => {
    if (hostId) ssaiRender(hostId);
    ssaiApply(SSAI_LANG);
    _ssaiUpdateBtn(SSAI_LANG);
  });
}